MERGE INTO drug AS target
USING drug_data AS source
ON target.drugcode = source.drugcode
WHEN MATCHED THEN
    UPDATE SET
        drugname = source.drugname,
        genericname = source.genericname,
        brandname = source.brandname,
        manufacturer = source.manufacturer,
        category = source.category,
        hsncode = source.hsncode,
        scheduletype = source.scheduletype,
        packing = source.packing,
        strength = source.strength,
        modifiedon = CURRENT_TIMESTAMP
WHEN NOT MATCHED THEN
    INSERT (
        drugcode, drugname, genericname, brandname, manufacturer,
        category, hsncode, scheduletype, packing, strength,
        isactive, createdby, createdon, modifiedby, modifiedon
    )
    VALUES (
        source.drugcode, source.drugname, source.genericname, source.brandname, source.manufacturer,
        source.category, source.hsncode, source.scheduletype, source.packing, source.strength,
        true, NULL, CURRENT_TIMESTAMP, NULL, NULL
    );